  1	import {
  2	  Alert,
  3	  Button,
  4	  Form,
  5	  FormGroup,
  6	  MenuToggle,
  7	  MenuToggleElement,
  8	  Modal,
  9	  ModalVariant,
 10	  Select,
 11	  SelectList,
 12	  SelectOption,
 13	} from "@patternfly/react-core";
 14	import * as React from "react";
 15	import { useNodeHealthCheckTranslation } from "localization/useNodeHealthCheckTranslation";
 16	import { useField, useFormikContext } from "formik";
 17	import { useRemediationTemplateCRDs } from "../../../../apis/useRemediationTemplateCRDs";
 18	
 19	type CustomKindModalProps = {
 20	  onClose(): void;
 21	  fieldName: string;
 22	};
 23	
 24	type CustomKindModalContentProps = {
 25	  selectedCRD: string | undefined;
 26	  onCRDSelect: (value: string | undefined) => void;
 27	  crds: ReturnType<typeof useRemediationTemplateCRDs>[0];
 28	  crdsLoaded: ReturnType<typeof useRemediationTemplateCRDs>[1];
 29	  crdsError: ReturnType<typeof useRemediationTemplateCRDs>[2];
 30	};
 31	
 32	const CustomKindModalContent: React.FC<CustomKindModalContentProps> = ({
 33	  selectedCRD,
 34	  onCRDSelect,
 35	  crds,
 36	  crdsLoaded,
 37	  crdsError,
 38	}) => {
 39	  const { t } = useNodeHealthCheckTranslation();
 40	  const [isCRDSelectOpen, setIsCRDSelectOpen] = React.useState(false);
 41	
 42	  const getCRDToggleLabel = () => {
 43	    if (!crdsLoaded) {
 44	      return t("Loading");
 45	    }
 46	    if (selectedCRD) {
 47	      return selectedCRD;
 48	    }
 49	    return t("Select a Kind");
 50	  };
 51	
 52	  if (crdsError) {
 53	    return (
 54	      <Form>
 55	        <FormGroup>
 56	          <Alert variant="danger" title={t("Error loading CRDs")} isInline>
 57	            {t("Could not load CustomResourceDefinitions.")}
 58	          </Alert>
 59	        </FormGroup>
 60	      </Form>
 61	    );
 62	  }
 63	
 64	  return (
 65	    <Form>
 66	      {crds.length === 0 && crdsLoaded && (
 67	        <FormGroup>
 68	          <Alert variant="warning" title={t("No CRDs available")} isInline>
 69	            {t(
 70	              "No CustomResourceDefinitions with remediation template structure (spec.template.spec) were found in the cluster besides the predefined supported ones. Please select from predefined remediation template kinds or install remediation template operators to use custom kinds."
 71	            )}
 72	          </Alert>
 73	        </FormGroup>
 74	      )}
 75	      <FormGroup fieldId="crd-select" label={t("Kind")} isRequired>
 76	        <Select
 77	          id="crd-select"
 78	          isOpen={isCRDSelectOpen}
 79	          selected={selectedCRD}
 80	          onSelect={(
 81	            _event: React.MouseEvent<Element, MouseEvent> | undefined,
 82	            value: string | number | undefined
 83	          ) => {
 84	            if (value && typeof value === "string") {
 85	              onCRDSelect(value);
 86	            }
 87	            setIsCRDSelectOpen(false);
 88	          }}
 89	          onOpenChange={setIsCRDSelectOpen}
 90	          toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
 91	            <MenuToggle
 92	              ref={toggleRef}
 93	              onClick={() => setIsCRDSelectOpen(!isCRDSelectOpen)}
 94	              isExpanded={isCRDSelectOpen}
 95	              isFullWidth
 96	              isDisabled={!crdsLoaded || crds.length === 0}
 97	            >
 98	              {crds.length === 0 && crdsLoaded
 99	                ? t("No CRDs available")
100	                : getCRDToggleLabel()}
101	            </MenuToggle>
102	          )}
103	          maxMenuHeight="25rem"
104	          isScrollable
105	        >
106	          <SelectList>
107	            {crds.map((crd) => (
108	              <SelectOption
109	                key={crd.kind}
110	                value={crd.kind}
111	                description={crd.apiVersion}
112	              >
113	                {crd.kind}
114	              </SelectOption>
115	            ))}
116	          </SelectList>
117	        </Select>
118	      </FormGroup>
119	    </Form>
120	  );
121	};
122	
123	const CustomKindModal: React.FC<CustomKindModalProps> = ({
124	  fieldName,
125	  onClose,
126	}) => {
127	  const { t } = useNodeHealthCheckTranslation();
128	  const { setFieldValue } = useFormikContext();
129	  const kindFieldName = `${fieldName}.kind`;
130	  const apiVersionFieldName = `${fieldName}.apiVersion`;
131	  const [, , { setValue }] = useField(kindFieldName);
132	  const [selectedCRD, setSelectedCRD] = React.useState<string | undefined>(
133	    undefined
134	  );
135	  const [crds, crdsLoaded, crdsError] = useRemediationTemplateCRDs();
136	
137	  const selectedCRDObj = React.useMemo(() => {
138	    if (!selectedCRD) return undefined;
139	    return crds.find((crd) => crd.kind === selectedCRD);
140	  }, [selectedCRD, crds]);
141	
142	  const handleConfirm = () => {
143	    if (selectedCRDObj) {
144	      // Set both kind and apiVersion when CRD is selected
145	      setValue(selectedCRDObj.kind);
146	      setFieldValue(apiVersionFieldName, selectedCRDObj.apiVersion);
147	    }
148	    onClose();
149	  };
150	
151	  const canProceed =
152	    crdsLoaded && !crdsError && crds.length > 0 && selectedCRD !== undefined;
153	
154	  return (
155	    <Modal
156	      isOpen={true}
157	      onClose={onClose}
158	      variant={ModalVariant.small}
159	      title={t("Use custom kind")}
160	      description={t(
161	        "Select from CustomResourceDefinitions that have the spec.template.spec field structure and are not the officially supported remediation template kinds."
162	      )}
163	      data-test="use-custom-kind-modal"
164	      actions={[
165	        <Button
166	          key="confirm"
167	          variant="primary"
168	          onClick={handleConfirm}
169	          isDisabled={!canProceed}
170	          data-test="confirm-custom-kind"
171	          type="submit"
172	        >
173	          {t("OK")}
174	        </Button>,
175	        <Button
176	          key="cancel"
177	          variant="link"
178	          onClick={onClose}
179	          data-test="cancel-custom-kind"
180	        >
181	          {t("Cancel")}
182	        </Button>,
183	      ]}
184	    >
185	      <CustomKindModalContent
186	        selectedCRD={selectedCRD}
187	        onCRDSelect={setSelectedCRD}
188	        crds={crds}
189	        crdsLoaded={crdsLoaded}
190	        crdsError={crdsError}
191	      />
192	    </Modal>
193	  );
194	};
195	
196	export default CustomKindModal;

