126	const CustomKindModal: React.FC<CustomKindModalProps> = ({
127	  fieldName,
128	  onClose,
129	}) => {
130	  const { t } = useNodeHealthCheckTranslation();
131	  const { setFieldValue } = useFormikContext();
132	  const kindFieldName = `${fieldName}.kind`;
133	  const apiVersionFieldName = `${fieldName}.apiVersion`;
134	  const [, , { setValue }] = useField(kindFieldName);
135	  const [selectedCRD, setSelectedCRD] = React.useState<string | undefined>(
136	    undefined
137	  );
138	  const [crds, crdsLoaded, crdsError] = useRemediationTemplateCRDs();
139	
140	  const selectedCRDObj = React.useMemo(() => {
141	    if (!selectedCRD) return undefined;
142	    return crds.find((crd) => crd.kind === selectedCRD);
143	  }, [selectedCRD, crds]);
144	
145	  const handleConfirm = () => {
146	    if (selectedCRDObj) {
147	      // Set both kind and apiVersion when CRD is selected
148	      setValue(selectedCRDObj.kind);
149	      setFieldValue(apiVersionFieldName, selectedCRDObj.apiVersion);
150	    }
151	    onClose();
152	  };
153	
154	  const canProceed =
155	    crdsLoaded && !crdsError && crds.length > 0 && selectedCRD !== undefined;
156	
157	  return (
158	    <Modal
159	      isOpen={true}
160	      onClose={onClose}
161	      variant={ModalVariant.small}
162	      data-test="use-custom-kind-modal"
163	    >
164	      <ModalHeader
165	        title={t("Use custom kind")}
166	        description={t(
167	          "Select from CustomResourceDefinitions that have the spec.template.spec field structure and are not the officially supported remediation template kinds."
168	        )}
169	      />
170	      <ModalBody>
171	        <CustomKindModalContent
172	          selectedCRD={selectedCRD}
173	          onCRDSelect={setSelectedCRD}
174	          crds={crds}
175	          crdsLoaded={crdsLoaded}
176	          crdsError={crdsError}
177	        />
178	      </ModalBody>
179	      <ModalFooter>
180	        <Button
181	          key="confirm"
182	          variant="primary"
183	          onClick={handleConfirm}
184	          isDisabled={!canProceed}
185	          data-test="confirm-custom-kind"
186	          type="submit"
187	        >
188	          {t("OK")}
189	        </Button>
190	        <Button
191	          key="cancel"
192	          variant="link"
193	          onClick={onClose}
194	          data-test="cancel-custom-kind"
195	        >
196	          {t("Cancel")}
197	        </Button>
198	      </ModalFooter>
199	    </Modal>
200	  );
201	};
